## Pseudo-code
```typescript
export function computePodMetrics(pod: Pod): PodMetrics {
  const totalCapacity = computeCapacity(pod.capacity).total;
  let humanLoad = 0;
  let frameLoad = 0;
  let confidenceSum = 0;
  let confidenceCount = 0;
  let flaggedCount = 0;
  let reGroomCount = 0;

  for (const epic of pod.epics) {
    const band = computeVariance(epic);
    if (band === 'flagged') {
      flaggedCount++;
      continue; // CRITICAL: exclude from load
    }
    if (band === 're-groom') reGroomCount++;

    if (epic.humanEstimate !== null) humanLoad += epic.humanEstimate;
    if (epic.frameResult) {
      frameLoad += epic.frameResult.frameEstimate;
      confidenceSum += epic.frameResult.confidence;
      confidenceCount++;
    }
  }

  return {
    totalCapacity,
    humanLoad,
    frameLoad,
    balance: totalCapacity - frameLoad,
    avgConfidence: confidenceCount > 0 ? confidenceSum / confidenceCount : 0,
    epicCount: pod.epics.length,
    flaggedCount,
    reGroomCount,
  };
}
```

3. Add tests to verify:
   - Flagged epics NOT included in humanLoad/frameLoad
   - Empty pod returns zeros
   - Balance = totalCapacity - frameLoad

