import { AIEstimator, Epic, ReferenceEpic, AnalysisEvent, FrameResult } from '@/domain/brp';
import { AnalysisEventSchema } from './schemas';

function hashCode(str: string): number {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) - hash) + str.charCodeAt(i);
    hash |= 0;
  }
  return Math.abs(hash);
}

export function createSimulatedEstimator(): AIEstimator {
  return {
    async *analyzeEpic(epic: Epic, refs: ReferenceEpic[]): AsyncIterable<AnalysisEvent> {
      yield { kind: 'started', epicId: epic.id };
      yield { kind: 'progress', epicId: epic.id, pct: 0.5 };

      const seed = hashCode(epic.id);
      const frameEstimate = FIBONACCI_POINTS[seed % FIBONACCI_POINTS.length];
      // Generate breakdown summing to frameEstimate...
      const result: FrameResult = { /* deterministic based on seed */ };

      yield { kind: 'done', epicId: epic.id, result };
    }
  };
}

